const raw = $input.first().json;
  const text = raw.content?.[0]?.text || raw.body?.content?.[0]?.text
  || '';
  if (!text) {
    throw new Error('No text found in API response: ' +
  JSON.stringify(raw).slice(0, 500));
  }
  const cleaned = text.replace(/```json?\n?/g, '').replace(/```/g,
  '').trim();                                                          
  const parsed = JSON.parse(cleaned);
  return [{ json: parsed }];

const data = $input.first().json;
const title = data.meeting_title || 'Meeting Notes';
const date = data.meeting_date || '';
const time = data.meeting_time || '';
const summary = data.summary || '';
const attendees = data.attendees || [];
const items = data.action_items || [];
const nextMeeting = data.next_meeting || '';

const colors = ['#4F46E5', '#0d9488', '#d97706', '#dc2626', '#7c3aed', '#059669', '#e11d48', '#2563eb'];

// Group action items by owner
const grouped = {};
const ownerOrder = [];
items.forEach(item => {
  const owner = item.owner || 'Unassigned';
  if (!grouped[owner]) { grouped[owner] = []; ownerOrder.push(owner); }
  grouped[owner].push(item);
});

// Attendee pills
let attendeeHtml = '';
if (attendees.length) {
  attendeeHtml = '<p style="font-size:14px;font-weight:600;color:#4F46E5;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 12px 0">Attendees</p>';
  attendeeHtml += '<div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:24px">';
  attendees.forEach((a, i) => {
    const c = colors[i % colors.length];
    attendeeHtml += `<span style="background:${c}15;color:${c};border-radius:20px;padding:4px 12px;font-size:13px;font-weight:500">${a.name}</span>`;
  });
  attendeeHtml += '</div>';
}

// Summary block
let summaryHtml = '';
if (summary) {
  summaryHtml = `<p style="font-size:14px;font-weight:600;color:#4F46E5;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 12px 0">Summary</p>`;
  summaryHtml += `<div style="font-size:15px;line-height:1.7;color:#1f2937;background:#f9fafb;border-left:4px solid #4F46E5;padding:16px 20px;border-radius:0 8px 8px 0;margin:0 0 28px 0">${summary}</div>`;
}

// Owner-grouped action item blocks
let actionHtml = '';
if (ownerOrder.length) {
  actionHtml = '<p style="font-size:14px;font-weight:600;color:#4F46E5;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 12px 0">Action Items</p>';
  ownerOrder.forEach((owner, oi) => {
    const c = colors[oi % colors.length];
    actionHtml += `<div style="margin-bottom:16px;border-radius:8px;overflow:hidden;border-left:4px solid ${c}">`;
    actionHtml += `<div style="background:${c};padding:10px 16px;font-weight:700;font-size:14px;color:#fff">${owner}</div>`;
    grouped[owner].forEach((task, ti) => {
      const pri = (task.priority || 'Low').toLowerCase();
      const priLabel = task.priority || 'Low';
      let priBg, priColor;
      if (pri === 'high') { priBg = '#fee2e2'; priColor = '#dc2626'; }
      else if (pri === 'med') { priBg = '#fef3c7'; priColor = '#d97706'; }
      else { priBg = '#e0f2fe'; priColor = '#0284c7'; }
      const border = ti < grouped[owner].length - 1 ? 'border-bottom:1px solid #f3f4f6;' : '';
      actionHtml += `<div style="padding:10px 16px;display:flex;align-items:center;background:#fff;${border}">`;
      actionHtml += `<span style="flex:1;color:#1f2937;font-size:13px;font-weight:500">${task.task}</span>`;
      actionHtml += `<div style="display:flex;gap:10px;align-items:center;margin-left:auto">`;
      actionHtml += `<span style="color:#374151;font-size:12px;font-weight:600">${task.due}</span>`;
      actionHtml += `<span style="font-size:11px;font-weight:700;padding:2px 8px;border-radius:10px;background:${priBg};color:${priColor}">${priLabel}</span>`;
      actionHtml += '</div></div>';
    });
    actionHtml += '</div>';
  });
}

// Next meeting
let nextHtml = '';
if (nextMeeting) {
  nextHtml = `<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:6px;padding:12px 16px;font-size:13px;color:#166534;margin-top:24px"><strong>Next Meeting:</strong> ${nextMeeting}</div>`;
}

const subject = date ? `${title} — ${date}` : `Meeting Recap — ${title}`;

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;color:#1a1a1a;margin:0;padding:0;background:#f5f5f5">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f5"><tr><td align="center">
<table width="1000" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:8px;overflow:hidden">
  <tr><td style="background:#4F46E5;color:#fff;padding:24px 32px">
    <h1 style="font-size:20px;margin:0 0 4px 0">${title}</h1>
    <p style="font-size:13px;opacity:0.85;margin:0">${date}${time ? ' &nbsp;&nbsp; ' + time : ''}</p>
  </td></tr>
  <tr><td style="padding:24px 32px">
    ${summaryHtml}
    ${attendeeHtml}
    ${actionHtml}
    ${nextHtml}
  </td></tr>
  <tr><td style="padding:24px 32px 16px 32px;font-size:12px;color:#9ca3af;text-align:center">
    <p style="margin:0">Extracted automatically by Meeting Action Item Extractor</p>
    <p style="font-size:1px;color:#ffffff;opacity:0.01;margin:0">&#8204;</p>
  </td></tr>
</table>
</td></tr></table>
</body></html>`;

return [{ json: { emailBody: { from: 'onboarding@resend.dev', to: ['noorullah1102@gmail.com'], subject, html } } }];
